25459	        ds4_engine *e,
25460	        bool        load_slice,
25461	        uint32_t    load_layer_start,
25462	        uint32_t    load_layer_end) {
25463	#ifdef DS4_NO_GPU
25464	    (void)e;
25465	    (void)load_slice;
25466	    (void)load_layer_start;
25467	    (void)load_layer_end;
25468	    return true;
25469	#else
25470	    if (!e ||
25471	        e->backend != DS4_BACKEND_METAL ||
25472	        e->ssd_streaming ||
25473	        DS4_MODEL_VARIANT != DS4_VARIANT_PRO ||
25474	        getenv("DS4_METAL_DISABLE_PRO_Q4_EXPERT_TABLE_PRELOAD") != NULL) {
25475	        return true;
25476	    }
25477	    if (!metal_graph_q4_non_streaming_opt_in_enabled()) {
25478	        return true;
25479	    }
25480	    if (ds4_gpu_pro_q4_expert_table_auto_available() == 0 &&
25481	        getenv("DS4_METAL_ENABLE_PRO_Q4_EXPERT_TABLE_AUTO") == NULL &&
25482	        getenv("DS4_METAL_ENABLE_PRO_Q4_EXPERT_ADDRESS_AUTO") == NULL &&
25483	        getenv("DS4_METAL_ENABLE_Q4_EXPERT_TABLE") == NULL &&
25484	        getenv("DS4_METAL_ENABLE_Q4_EXPERT_ADDRESS_TABLE") == NULL) {
25485	        return true;
25486	    }
25487	
25488	    uint32_t start = load_slice ? load_layer_start : 0;
25489	    uint32_t end = load_slice ? load_layer_end : DS4_N_LAYER - 1u;
25490	    if (start >= DS4_N_LAYER) return true;
25491	    if (end == UINT32_MAX || end >= DS4_N_LAYER) end = DS4_N_LAYER - 1u;
25492	    if (end < start) return true;
25493	
25494	    bool any = false;
25495	    const double t0 = now_sec();
25496	    for (uint32_t il = start; il <= end; il++) {
25497	        const ds4_layer_weights *layer = &e->weights.layer[il];
25498	        if (!layer->ffn_gate_exps || !layer->ffn_up_exps || !layer->ffn_down_exps) {
25499	            continue;
25500	        }
25501	        if (layer->ffn_gate_exps->type != DS4_TENSOR_Q4_K ||
25502	            layer->ffn_up_exps->type != DS4_TENSOR_Q4_K ||
25503	            layer->ffn_down_exps->type != DS4_TENSOR_Q4_K ||
25504	            DS4_N_EXPERT != 384 ||
25505	            DS4_N_EXPERT_USED != 6) {
25506	            continue;
25507	        }
25508	
25509	        const uint64_t gate_row_bytes = routed_expert_row_bytes(layer->ffn_gate_exps);
25510	        const uint64_t down_row_bytes = routed_expert_row_bytes(layer->ffn_down_exps);
25511	        if (layer->ffn_gate_exps->dim[1] > UINT64_MAX / gate_row_bytes ||
25512	            layer->ffn_down_exps->dim[1] > UINT64_MAX / down_row_bytes) {
25513	            fprintf(stderr, "ds4: PRO Q4 expert table preload byte size overflow at layer %u\n", il);
25514	            return false;
25515	        }
25516	        const uint64_t gate_expert_bytes = layer->ffn_gate_exps->dim[1] * gate_row_bytes;
25517	        const uint64_t down_expert_bytes = layer->ffn_down_exps->dim[1] * down_row_bytes;
25518	
25519	        if (!ds4_gpu_preload_q4_expert_tables(e->model.map,
25520	                                              e->model.size,
25521	                                              layer->ffn_gate_exps->abs_offset,
25522	                                              layer->ffn_up_exps->abs_offset,
25523	                                              layer->ffn_down_exps->abs_offset,
25524	                                              gate_expert_bytes,
25525	                                              down_expert_bytes,
25526	                                              DS4_N_EXPERT)) {
25527	            fprintf(stderr,
25528	                    "ds4: Metal failed to preload PRO Q4 expert tables for layer %u\n",
25529	                    il);
25530	            return false;
25531	        }
25532	        any = true;
25533	    }
25534	
25535	    if (any) {
25536	        fprintf(stderr,
25537	                "ds4: Metal preloaded PRO Q4 expert tables for layers %u:%u in %.2fs\n",
25538	                start,
25539	                end,
25540	                now_sec() - t0);
25541	    }
25542	    return true;
25543	#endif
25544	}
