        uint32_t slot,
        uint32_t *slab_index,
        uint64_t *slot_base) {
    for (uint32_t i = 0; i < g_stream_expert_cache_slab_count; i++) {
        const uint32_t start = g_stream_expert_cache_slab_start_slot[i];
        const uint32_t count = g_stream_expert_cache_slab_slot_count[i];
